mapper.select:
/*
	 토론 게시글 수 카운팅
	 ForumAtclDAO.forumAtclCount
*/
SELECT COUNT(*)
  FROM TB_LMS_DSCS_ATCL
 WHERE RGTR_ID = #{rgtrId}
   AND DSCS_ID = #{forumCd}
   AND DELYN = 'N'

/* 토론 게시글의 검색된 수를 카운팅 ForumAtclDAO.count */ SELECT COUNT(*) FROM (SELECT A.ATCL_ID AS AtclSn , A.DSCS_ID AS forumCd , A.UP_ATCL_ID AS parAtclSn , A.ATCL_LV AS atclLvl , A.ATCL_SEQ AS atclOdr , A.ATCL_TYCD AS atclTypeCd , A.OKNOK_TYCD AS prosConsTypeCd , A.TTL AS TTL , A.SND_CTS AS SND_CTS , A.INQ_CNT AS INQ_CNT , A.RGTRNM AS regNm , A.RGTR_ID AS rgtrId , A.FRST_INQ_DTTM AS regDttm , A.MDFR_ID AS mdfrId , A.MOD_DTTM AS modDttm , A.EDTRYN AS editorYn , A.DELYN AS delYn , ( SELECT COUNT(*) FROM TB_LMS_DSCS_CMNT B WHERE B.ATCL_ID = A.ATCL_ID AND B.DELYN = 'N' ) AS cmntCount , ( SELECT MAX(B.ATCL_SEQ) FROM TB_LMS_DSCS_ATCL B WHERE B.DSCS_ID = A.DSCS_ID AND B.DELYN = 'N' ) AS maxOdr , A.STD_ID AS stdNo , ( SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = A.RGTR_ID ) AS userId FROM TB_LMS_DSCS_ATCL A WHERE 1 = 1 AND A.DSCS_ID = #{forumCd}
AND (A.STD_ID IN
#{item}
OR A.OKNOK_TYCD IN ('F') )
AND A.DELYN ='N'
AND ( LOWER(A.STD_ID) = ( SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE USER_ID = (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = #{searchValue}) AND SBJCT_ID = #{crsCreCd} AND ATNDLC_STSCD = 'S' ) ) UNION ALL SELECT A.ATCL_ID AS atclSn , A.UP_ATCL_ID AS parAtclSn , A.DSCS_ID AS forumCd , A.ATCL_LV AS atclLvl , A.ATCL_SEQ AS atclOdr , A.ATCL_TYCD AS atclTypeCd , A.OKNOK_TYCD AS prosConsTypeCd , A.TTL AS TTL , A.SND_CTS AS SND_CTS , A.INQ_CNT AS INQ_CNT , A.RGTRNM AS regNm , A.RGTR_ID AS rgtrId , A.FRST_INQ_DTTM AS regDttm , A.MDFR_ID AS mdfrId , A.MOD_DTTM AS modDttm , A.EDTRYN AS editorYn , A.DELYN AS delYn , ( SELECT COUNT(*) FROM TB_LMS_DSCS_CMNT AS B WHERE B.ATCL_ID = A.ATCL_ID AND B.DELYN = 'N' ) AS cmntCount , ( SELECT MAX(B.ATCL_SEQ) FROM TB_LMS_DSCS_ATCL AS B WHERE B.DSCS_ID = A.DSCS_ID AND B.DELYN = 'N' ) AS maxOdr , A.STD_ID AS stdNo , ( SELECT IFNULL(USER_ID, A.RGTR_ID) FROM TB_LMS_USER_ACNT WHERE USER_ID = A.RGTR_ID ) AS userId FROM TB_LMS_DSCS_ATCL A WHERE 1 = 1 AND A.DSCS_ID = #{forumCd} AND A.STD_ID != ( SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE USER_ID = ( SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = #{searchValue}) AND SBJCT_ID = #{crsCreCd} AND ATNDLC_STSCD = 'S' ) AND EXISTS ( SELECT 1 FROM TB_LMS_DSCS_CMNT C WHERE C.DSCS_ID = A.DSCS_ID AND C.ATCL_ID = A.ATCL_ID AND C.STD_ID = ( SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE USER_ID = ( SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = #{searchValue} ) AND SBJCT_ID = #{crsCreCd} AND ATNDLC_STSCD = 'S' ) )
ORDER BY atclOdr ASC , regDttm DESC ) T WHERE (T.delYn ='N' OR T.cmntCount > 0)

/* 토론 게시글 페이징 목록을 조회 ForumAtclDAO.listPageing */
SELECT ROW_NUMBER() OVER(ORDER BY regSort ASC, atclOdr ASC, regDttm DESC) AS LINE_NO , atclSn , forumCd , parAtclSn , atclLvl , atclOdr , atclTypeCd , prosConsTypeCd , TTL , (SELECT SND_CTS FROM TB_LMS_DSCS_ATCL WHERE ATCL_ID = A.atclSn) AS SND_CTS , ctsLen , INQ_CNT , regNm , rgtrId , regDttm , mdfrId , modDttm , editorYn , delYn , konanMaxCopyRate , (SELECT COUNT(1) FROM TB_LMS_DSCS_CMNT WHERE ATCL_ID = A.atclSn AND DELYN = 'N') AS cmntCount , (SELECT MAX(ATCL_SEQ) FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = A.forumCd AND DELYN = 'N') AS maxOdr , stdNo , (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = A.rgtrId) AS userId , afterAtclCnt , (SELECT PHT_FILE FROM TB_LMS_USR WHERE USER_ID = A.rgtrId) AS PTH_FILE_BYTE , NVL((SELECT APLY_CMNT_RSPNSYN FROM TB_LMS_DSCS WHERE DSCS_ID = A.forumCd), 'N') AS aplyAsnYn FROM ( SELECT atclSn , forumCd , parAtclSn , atclLvl , atclOdr , atclTypeCd , prosConsTypeCd , TTL , ctsLen , INQ_CNT , regNm , rgtrId , regDttm , mdfrId , modDttm , editorYn , delYn , konanMaxCopyRate , stdNo , afterAtclCnt , regSort FROM (SELECT A.ATCL_ID AS atclSn , A.DSCS_ID AS forumCd , A.UP_ATCL_ID AS parAtclSn , A.ATCL_LV AS atclLvl , A.ATCL_SEQ AS atclOdr , A.ATCL_TYCD AS atclTypeCd , A.OKNOK_TYCD AS prosConsTypeCd , A.TTL AS TTL , A.ATCL_CTS_LEN AS ctsLen , A.INQ_CNT AS INQ_CNT , A.RGTRNM AS regNm , A.RGTR_ID AS rgtrId , A.FRST_INQ_DTTM AS regDttm , A.MDFR_ID AS mdfrId , A.MOD_DTTM AS modDttm , A.EDTRYN AS editorYn , A.DELYN AS delYn , A.KONAN_MAX_MOSART AS konanMaxCopyRate , A.STD_ID AS stdNo , (SELECT COUNT(1) FROM TB_LMS_DSCS AA WHERE 1 = 1 AND A.FRST_INQ_DTTM BETWEEN AA.DSCS_EDTTM AND AA.EXTD_EDTTM AND AA.DSCS_ID = A.DSCS_ID AND AA.DELYN = 'N') AS afterAtclCnt , 1 AS regSort FROM TB_LMS_DSCS_ATCL A WHERE 1 = 1 AND A.DSCS_ID = #{forumCd} AND A.DELYN = 'N'
AND (A.STD_ID IN
#{item}
)
) T WHERE 1 = 1
AND T.afterAtclCnt > 0
AND ( LOWER(T.stdNo) = (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE USER_ID = #{searchValue} AND SBJCT_ID = #{crsCreCd} AND ATNDLC_STSCD = 'S') OR T.regNm LIKE FN_LIKE_VAL(LOWER(#{searchValue})) ) UNION ALL SELECT A.ATCL_ID AS atclSn , A.DSCS_ID AS forumCd , A.UP_ATCL_ID AS parAtclSn , A.ATCL_LV AS atclLvl , A.ATCL_SEQ AS atclOdr , A.ATCL_TYCD AS atclTypeCd , A.OKNOK_TYCD AS prosConsTypeCd , A.TTL AS TTL , A.ATCL_CTS_LEN AS ctsLen , A.INQ_CNT AS INQ_CNT , A.RGTRNM AS regNm , A.RGTR_ID AS rgtrId , A.FRST_INQ_DTTM AS regDttm , A.MDFR_ID AS mdfrId , A.MOD_DTTM AS modDttm , A.EDTRYN AS editorYn , A.DELYN AS delYn , A.KONAN_MAX_MOSART AS konanMaxCopyRate , A.STD_ID AS stdNo , (SELECT COUNT(1) FROM TB_LMS_DSCS AA WHERE 1 = 1 AND A.FRST_INQ_DTTM BETWEEN AA.DSCS_EDTTM AND AA.EXTD_EDTTM AND AA.DSCS_ID = A.DSCS_ID AND AA.DELYN = 'N') AS afterAtclCnt , 2 AS regSort FROM TB_LMS_DSCS_ATCL A WHERE 1 = 1 AND A.DSCS_ID = #{forumCd} AND (A.STD_ID != (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE USER_ID = #{searchValue} AND SBJCT_ID = #{crsCreCd} AND ATNDLC_STSCD = 'S') OR A.RGTR_ID LIKE FN_LIKE_VAL(LOWER(#{searchValue}))) AND EXISTS (SELECT 1 FROM TB_LMS_DSCS_CMNT C WHERE C.DSCS_ID = A.DSCS_ID AND C.ATCL_ID = A.ATCL_ID AND ( C.STD_ID = (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE USER_ID = #{searchValue} AND SBJCT_ID = #{crsCreCd} AND ATNDLC_STSCD = 'S') OR C.RGTR_ID LIKE FN_LIKE_VAL(LOWER(#{searchValue})) ) )
) A ORDER BY regSort ASC, atclOdr ASC, regDttm DESC, cmntCount DESC

mapper.insert:
/*
	 토론글 등록
	 ForumAtclVO.insertAtcl
*/
INSERT INTO TB_LMS_DSCS_ATCL (
	ATCL_ID
	, DSCS_ID
	, UP_ATCL_ID
	, ATCL_LV
	, ATCL_SEQ
	, ATCL_TYCD
	, OKNOK_TYCD
	, TTL
	, SND_CTS
	, INQ_CNT
	, STD_ID 
	, RGTRNM
	, RGTR_ID
	, FRST_INQ_DTTM
	, MDFR_ID
	, MOD_DTTM
	, EDTRYN
	, DELYN
	, ATCL_CTS_LEN
) VALUES (
	#{atclSn}
	, #{forumCd}
	, #{parAtclSn}
	, 0
	, #{atclOdr}
	, #{atclTypeCd}
	, #{prosConsTypeCd}
	, #{TTL}
	, #{SND_CTS}
	, #{INQ_CNT}
	, IFNULL(FN_GET_STD_NO(#{userId}, #{crsCreCd}),'') 
	, #{regNm}
	, #{rgtrId}
	, FN_DTTM()
	, #{mdfrId}
	, FN_DTTM()
	, 'N'
	, 'N'
	, #{ctsLen}
)

mapper.update:
/*
	 토론 게시글 수정
	 ForumAtclDAO.updateAtcl
*/
UPDATE TB_LMS_DSCS_ATCL
   SET MDFR_ID = #{mdfrId}
	, MOD_DTTM = FN_DTTM()

	, UP_ATCL_ID = #{parAtclSn}


	, ATCL_LV = #{atclLvl}


	, ATCL_SEQ = #{atclOdr}


	, ATCL_TYCD = #{atclTypeCd}


	, OKNOK_TYCD = #{prosConsTypeCd}


	, TTL = #{TTL}


	, SND_CTS = #{SND_CTS}
	, ATCL_CTS_LEN = #{ctsLen}


	, INQ_CNT = #{inqCnt}


	, EDTRYN = #{editorYn}


	, DELYN = #{delYn}

 WHERE ATCL_ID = #{atclSn}
   AND DSCS_ID = #{forumCd}

/*
	 토론 게시글 삭제
	 ForumAtclDAO.deleteAtcl
*/
UPDATE TB_LMS_DSCS_ATCL
   SET DELYN = 'Y'
	   , MDFR_ID = #{mdfrId}
	   , MOD_DTTM = FN_DTTM()
 WHERE ATCL_ID = #{atclSn}
   AND DSCS_ID = #{forumCd}
